def recursive_summarize(self, document, chunk_size=1500):
    tokens = self.tokenizer(document, return_tensors='pt')['input_ids'].squeeze()
    num_tokens = len(tokens)
    # Direct summarize if within context window
    if num_tokens < 2000:
        return self.summarize_chunk(document)
    # Chunk → summarize → recombine → final summarize
    summaries = []
    for i in range(0, num_tokens, chunk_size):
        chunk_ids = tokens[i: i + chunk_size]
        chunk_text = self.tokenizer.decode(chunk_ids, skip_special_tokens=True)
        summaries.append(self.summarize_chunk(chunk_text))
    combined = ' '.join(summaries)
    return self.summarize_chunk(combined)
